import json
import re
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)

# Elasticsearch client configuration
es = Elasticsearch(
    hosts=[{"host": "localhost", "port": 9200}],
    timeout=30
)

# Allowlist of safe aggregation types
ALLOWED_AGG_TYPES = {"sum", "avg", "min", "max", "value_count", "cardinality", "stats", "extended_stats"}

# Allowlist of safe script languages
ALLOWED_LANGUAGES = {"painless"}

# Pattern to detect dangerous operations in Painless scripts
DANGEROUS_PATTERNS = [
    r"Runtime\s*\.",
    r"ProcessBuilder",
    r"getRuntime",
    r"exec\s*\(",
    r"System\s*\.\s*exit",
    r"java\s*\.\s*lang\s*\.\s*Runtime",
    r"java\s*\.\s*io\s*\.",
    r"java\s*\.\s*net\s*\.",
    r"java\s*\.\s*nio\s*\.",
    r"Thread\s*\.",
    r"ClassLoader",
    r"Reflection",
    r"forName\s*\(",
    r"getClass\s*\(",
    r"getMethod\s*\(",
    r"invoke\s*\(",
    r"newInstance\s*\(",
    r"File\s*\(",
    r"Socket\s*\(",
    r"URL\s*\(",
    r"Process",
    r"import\s+",
    r"Class\s*\.\s*forName",
    r"ScriptEngine",
    r"GroovyShell",
    r"MethodHandle",
    r"Unsafe",
]


def validate_script(script_source):
    """Validate that a script does not contain dangerous operations."""
    if not isinstance(script_source, str):
        return False, "Script source must be a string"

    if len(script_source) > 500:
        return False, "Script source exceeds maximum length of 500 characters"

    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, script_source, re.IGNORECASE):
            return False, f"Script contains disallowed pattern: {pattern}"

    return True, "Script is valid"


def validate_field_name(field_name):
    """Validate field names to prevent injection."""
    if not isinstance(field_name, str):
        return False
    # Only allow alphanumeric, underscores, dots, and hyphens
    return bool(re.match(r'^[a-zA-Z0-9_.\-]+$', field_name)) and len(field_name) <= 256


def validate_index_name(index_name):
    """Validate index names to prevent injection."""
    if not isinstance(index_name, str):
        return False
    # Only allow alphanumeric, underscores, hyphens, and wildcards
    return bool(re.match(r'^[a-zA-Z0-9_\-\*]+$', index_name)) and len(index_name) <= 256


def build_scripted_metric_aggregation(config):
    """Build a scripted metric aggregation from validated config using stored scripts."""
    agg = {"scripted_metric": {}}

    for phase in ["init_script", "map_script", "combine_script", "reduce_script"]:
        if phase in config:
            script_source = config[phase]
            is_valid, message = validate_script(script_source)
            if not is_valid:
                raise ValueError(f"Invalid {phase}: {message}")
            agg["scripted_metric"][phase] = {
                "source": script_source,
                "lang": "painless"
            }

    return agg


def build_script_aggregation(agg_type, script_source, params=None):
    """Build a standard aggregation with a script field."""
    if agg_type not in ALLOWED_AGG_TYPES:
        raise ValueError(f"Aggregation type '{agg_type}' is not allowed. Allowed types: {ALLOWED_AGG_TYPES}")

    is_valid, message = validate_script(script_source)
    if not is_valid:
        raise ValueError(f"Invalid script: {message}")

    script_body = {
        "source": script_source,
        "lang": "painless"
    }

    if params:
        if not isinstance(params, dict):
            raise ValueError("Script params must be a dictionary")
        # Validate param keys
        for key in params:
            if not re.match(r'^[a-zA-Z0-9_]+$', str(key)):
                raise ValueError(f"Invalid parameter key: {key}")
        script_body["params"] = params

    return {
        agg_type: {
            "script": script_body
        }
    }


@app.route("/api/aggregation/script", methods=["POST"])
def execute_script_aggregation():
    """
    Execute a scripted aggregation against Elasticsearch.

    Expected JSON body:
    {
        "index": "my-index",
        "agg_type": "sum",  # One of the allowed aggregation types
        "agg_name": "my_aggregation",
        "script": "doc['price'].value * doc['quantity'].value",
        "params": {"factor": 1.5},  # Optional script parameters
        "query": {"match_all": {}},  # Optional query filter
        "size": 0  # Optional, defaults to 0
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        # Validate required fields
        index = data.get("index")
        if not index or not validate_index_name(index):
            return jsonify({"error": "Invalid or missing 'index' parameter"}), 400

        agg_type = data.get("agg_type")
        if not agg_type:
            return jsonify({"error": "Missing 'agg_type' parameter"}), 400

        script_source = data.get("script")
        if not script_source:
            return jsonify({"error": "Missing 'script' parameter"}), 400

        agg_name = data.get("agg_name", "script_agg")
        if not re.match(r'^[a-zA-Z0-9_\-]+$', str(agg_name)):
            return jsonify({"error": "Invalid aggregation name"}), 400

        params = data.get("params")
        query = data.get("query", {"match_all": {}})
        size = data.get("size", 0)

        if not isinstance(size, int) or size < 0 or size > 100:
            return jsonify({"error": "Size must be an integer between 0 and 100"}), 400

        # Build the aggregation
        agg_body = build_script_aggregation(agg_type, script_source, params)

        # Build the search body
        search_body = {
            "size": size,
            "query": query,
            "aggs": {
                agg_name: agg_body
            }
        }

        # Execute the search
        result = es.search(index=index, body=search_body)

        return jsonify({
            "aggregation": result.get("aggregations", {}).get(agg_name, {}),
            "hits_total": result.get("hits", {}).get("total", {}).get("value", 0)
        })

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        return jsonify({"error": f"Elasticsearch error: {str(e)}"}), 500


