        if not re.match(r'^[a-zA-Z0-9_\-]+$', str(agg_name)):
            return jsonify({"error": "Invalid aggregation name"}), 400

        query = data.get("query", {"match_all": {}})

        # Build scripted metric aggregation
        scripted_metric_config = {
            key: data[key]
            for key in ["init_script", "map_script", "combine_script", "reduce_script"]
            if key in data
        }

