@app.route("/api/stored_script", methods=["PUT"])
def create_stored_script():
    """
    Create/update a stored script in Elasticsearch (admin only).

    Expected JSON body:
    {
        "script_id": "calculate_total",
        "script_source": "doc['price'].value * params['factor']",
        "description": "Calculate total with factor"
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        script_id = data.get("script_id")
        if not script_id or not re.match(r'^[a-zA-Z0-9_\-]+$', str(script_id)):
            return jsonify({"error": "Invalid or missing 'script_id'"}), 400

        script_source = data.get("script_source")
        if not script_source:
            return jsonify({"error": "Missing 'script_source'"}), 400

        is_valid, message = validate_script(script_source)
        if not is_valid:
            return jsonify({"error": f"Invalid script: {message}"}), 400

        body = {
            "script": {
                "lang": "painless",
                "source": script_source
            }
        }

        description = data.get("description")
        if description and isinstance(description, str) and len(description) <= 500:
            body["script"]["description"] = description

        result = es.put_script(id=script_id, body=body)

        return jsonify({"result": "stored", "script_id": script_id})

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        return jsonify({"error": f"Elasticsearch error: {str(e)}"}), 500


@app.route("/api/health", methods=["GET"])
def health_check():
    """Check Elasticsearch cluster health."""
    try:
        health = es.cluster.health()
        return jsonify({
            "status": "ok",
            "cluster_status": health.get("status"),
            "cluster_name": health.get("cluster_name")
        })
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500


